import{_ as i,c as l,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/vitepress-开发工具.md","filePath":"github汇总/开发工具/vitepress-开发工具.md"}'),s={name:"github汇总/开发工具/vitepress-开发工具.md"};function h(n,a,t,d,o,p){return e(),l("div",null,a[0]||(a[0]=[r(`<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>VitePress</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Vue.js团队</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><ul><li>传统静态站点生成器配置复杂，上手门槛高</li><li>构建速度慢，开发体验不佳</li><li>热更新不及时，影响开发效率</li><li>缺少与Vue.js生态的深度集成</li></ul><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>基于Vite的静态站点生成器，启动和构建速度超快</li><li>支持Markdown写作，内置语法高亮</li><li>自动生成侧边栏导航</li><li>完整支持Vue组件，可在Markdown中直接使用</li><li>一键初始化项目，配置简单</li><li>支持自定义主题和插件扩展</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>Vue.js官方出品，质量有保障</li><li>基于Vite构建，速度极快</li><li>热更新即时生效，开发体验极佳</li><li>与Vue.js生态深度集成</li><li>上手简单，一键初始化</li><li>可扩展性强，支持主题和插件</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明，但作为Vue.js官方项目在开源社区有广泛影响力</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/vuejs/vitepress" target="_blank" rel="noreferrer">https://github.com/vuejs/vitepress</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>本教程适用于想要使用VitePress搭建技术文档或博客的开发者，支持Windows、macOS和Linux系统。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><h3 id="_1-node-js版本检查" tabindex="-1">1. Node.js版本检查 <a class="header-anchor" href="#_1-node-js版本检查" aria-label="Permalink to “1. Node.js版本检查”">​</a></h3><ul><li>步骤目标：确认Node.js版本满足要求</li><li>执行位置：本机终端</li><li>完整命令：<code>node --version</code></li><li>成功标志：显示Node.js 16.0或更高版本</li><li>失败处理：请安装或升级Node.js至16.0+版本</li></ul><h3 id="_2-npm或pnpm检查" tabindex="-1">2. npm或pnpm检查 <a class="header-anchor" href="#_2-npm或pnpm检查" aria-label="Permalink to “2. npm或pnpm检查”">​</a></h3><ul><li>步骤目标：确认包管理器可用</li><li>执行位置：本机终端</li><li>完整命令：<code>npm --version</code> 或 <code>pnpm --version</code></li><li>成功标志：显示包管理器版本信息</li><li>失败处理：请安装npm或pnpm</li></ul><h3 id="_3-网络访问检查" tabindex="-1">3. 网络访问检查 <a class="header-anchor" href="#_3-网络访问检查" aria-label="Permalink to “3. 网络访问检查”">​</a></h3><ul><li>步骤目标：确认可以访问npm仓库</li><li>执行位置：本机终端</li><li>完整命令：<code>ping registry.npmjs.org</code></li><li>成功标志：可以正常访问</li><li>失败处理：请检查网络连接或配置npm镜像源</li></ul><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><h3 id="步骤1-创建项目目录" tabindex="-1">步骤1：创建项目目录 <a class="header-anchor" href="#步骤1-创建项目目录" aria-label="Permalink to “步骤1：创建项目目录”">​</a></h3><ul><li>步骤目标：创建一个空的项目文件夹</li><li>执行位置：本机终端</li><li>完整命令：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mkdir my-docs</span></span>
<span class="line"><span>cd my-docs</span></span></code></pre></div></li><li>成功标志：进入新创建的目录</li><li>失败处理：确保有文件系统权限</li></ul><h3 id="步骤2-初始化vitepress项目" tabindex="-1">步骤2：初始化VitePress项目 <a class="header-anchor" href="#步骤2-初始化vitepress项目" aria-label="Permalink to “步骤2：初始化VitePress项目”">​</a></h3><ul><li>步骤目标：使用向导初始化VitePress项目</li><li>执行位置：项目目录终端</li><li>完整命令：<code>npx vitepress init</code></li><li>成功标志：启动初始化向导，按提示选择配置</li><li>失败处理：尝试使用pnpm：<code>pnpm dlx vitepress init</code></li></ul><h3 id="步骤3-安装依赖" tabindex="-1">步骤3：安装依赖 <a class="header-anchor" href="#步骤3-安装依赖" aria-label="Permalink to “步骤3：安装依赖”">​</a></h3><ul><li>步骤目标：安装项目所需的依赖包</li><li>执行位置：项目目录终端</li><li>完整命令：<code>npm install</code></li><li>成功标志：显示安装完成，无错误</li><li>失败处理：检查网络连接，或使用国内镜像源</li></ul><h3 id="步骤4-启动开发服务器" tabindex="-1">步骤4：启动开发服务器 <a class="header-anchor" href="#步骤4-启动开发服务器" aria-label="Permalink to “步骤4：启动开发服务器”">​</a></h3><ul><li>步骤目标：启动本地开发服务器预览站点</li><li>执行位置：项目目录终端</li><li>完整命令：<code>npm run docs:dev</code></li><li>成功标志：显示服务器启动成功，给出本地访问地址（通常是<a href="http://localhost:5173" target="_blank" rel="noreferrer">http://localhost:5173</a>）</li><li>失败处理：检查端口是否被占用，或查看错误信息</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><h3 id="_1-访问本地站点" tabindex="-1">1. 访问本地站点 <a class="header-anchor" href="#_1-访问本地站点" aria-label="Permalink to “1. 访问本地站点”">​</a></h3><ul><li>访问方式：浏览器</li><li>访问地址：<a href="http://localhost:5173" target="_blank" rel="noreferrer">http://localhost:5173</a></li><li>预期返回：看到VitePress默认页面</li></ul><h3 id="_2-测试热更新" tabindex="-1">2. 测试热更新 <a class="header-anchor" href="#_2-测试热更新" aria-label="Permalink to “2. 测试热更新”">​</a></h3><ul><li>访问方式：编辑docs/index.md文件</li><li>检查方法：修改文件内容后保存，浏览器应自动刷新显示更新</li><li>预期返回：页面即时更新</li></ul><h3 id="_3-构建生产版本" tabindex="-1">3. 构建生产版本 <a class="header-anchor" href="#_3-构建生产版本" aria-label="Permalink to “3. 构建生产版本”">​</a></h3><ul><li>访问方式：命令行</li><li>检查命令：<code>npm run docs:build</code></li><li>预期返回：构建成功，生成dist目录</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><h3 id="现象1-node-js版本过低" tabindex="-1">现象1：Node.js版本过低 <a class="header-anchor" href="#现象1-node-js版本过低" aria-label="Permalink to “现象1：Node.js版本过低”">​</a></h3><ul><li>可能原因：Node.js版本不满足最低要求</li><li>解决步骤： <ol><li>检查当前Node.js版本：node --version</li><li>下载并安装Node.js 16.0或更高版本</li><li>重新打开终端并验证版本</li></ol></li></ul><h3 id="现象2-依赖安装失败" tabindex="-1">现象2：依赖安装失败 <a class="header-anchor" href="#现象2-依赖安装失败" aria-label="Permalink to “现象2：依赖安装失败”">​</a></h3><ul><li>可能原因：网络问题或npm镜像源访问受限</li><li>解决步骤： <ol><li>检查网络连接</li><li>配置国内npm镜像源：npm config set registry <a href="https://registry.npmmirror.com" target="_blank" rel="noreferrer">https://registry.npmmirror.com</a></li><li>重新运行npm install</li></ol></li></ul><h3 id="现象3-端口被占用" tabindex="-1">现象3：端口被占用 <a class="header-anchor" href="#现象3-端口被占用" aria-label="Permalink to “现象3：端口被占用”">​</a></h3><ul><li>可能原因：5173端口已被其他程序占用</li><li>解决步骤： <ol><li>查找占用端口的程序并关闭</li><li>或修改VitePress配置使用其他端口</li><li>重新启动开发服务器</li></ol></li></ul><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><h3 id="使用pnpm安装" tabindex="-1">使用pnpm安装 <a class="header-anchor" href="#使用pnpm安装" aria-label="Permalink to “使用pnpm安装”">​</a></h3><ul><li>适用场景：偏好使用pnpm作为包管理器</li><li>完整命令：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pnpm add -D vitepress</span></span>
<span class="line"><span>pnpm vitepress init</span></span></code></pre></div></li></ul><h3 id="手动配置" tabindex="-1">手动配置 <a class="header-anchor" href="#手动配置" aria-label="Permalink to “手动配置”">​</a></h3><ul><li>适用场景：想要完全自定义配置</li><li>步骤： <ol><li>手动创建package.json</li><li>安装vitepress依赖</li><li>创建docs目录和配置文件</li></ol></li></ul><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>基于公开可验证信息整理，完整教程请参考官方文档。</p><p>更多详细文档请参考：</p><ul><li>VitePress官方文档：<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li>GitHub仓库：<a href="https://github.com/vuejs/vitepress" target="_blank" rel="noreferrer">https://github.com/vuejs/vitepress</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>`,58)]))}const m=i(s,[["render",h]]);export{b as __pageData,m as default};
